class Solution {
    // Minimum time to reach bottom right cell
    swimInWater(grid) {
        // Get grid size
        const n = grid.length;

        // Min-heap using priority queue logic
        const heap = [[grid[0][0], 0, 0]];

        // Visited matrix
        const visited = Array.from({ length: n }, () => Array(n).fill(false));
        visited[0][0] = true;

        // Direction vectors
        const dirs = [[0,1], [1,0], [0,-1], [-1,0]];

        // Custom min-heap sort function
        const sortHeap = () => heap.sort((a, b) => a[0] - b[0]);

        // Process heap
        while (heap.length > 0) {
            // Sort and pop lowest elevation
            sortHeap();
            const [elevation, r, c] = heap.shift();

            // Check if destination
            if (r === n - 1 && c === n - 1) return elevation;

            // Explore neighbors
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;

                // Check bounds and visited
                if (nr >= 0 && nc >= 0 && nr < n && nc < n && !visited[nr][nc]) {
                    visited[nr][nc] = true;
                    heap.push([Math.max(elevation, grid[nr][nc]), nr, nc]);
                }
            }
        }

        return -1;
    }
}

